	.TITLE	ESPION	.PROC	M680002	.RADIX	10.	.HEX	.REF	SM8	.REF	LIB	.REF	SM100HARDMIDI1	=	ACIA0+2			; Usart 6850 no 1 DATA.SMIDI1	=	ACIA0			; Usart 6850 no 1 CONTROL-STATUSMIDIMOD	=	B'00010110		; divise le clock par 64 BUSTINT=	B'00100000		; interrupt disable transmitERCVINT=	B'10000000		; interrupt disable receiveMASTRST	=	B'00000011		; soft resetVECTINT	=	D'29			; Numro vecteur d'interrupt.ADVINT	=	4*VECTINT		; Adresse du vecteur d'interrupt.LGMAX	=	10000	.LOC	0OLDATA:	.BLKB	4OBUFFER:.BLKB	LGMAXLGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	CLR.L	(A6)+OLDATA	LOAD.B	SMIDI1,#MASTRST		; reset 6850 SOFT	LOAD.B	SMIDI1,#MIDIMOD		; mode de transfert MIDI	LOAD.L	A0,#R16"ROUTINT	LOAD.L	ADVINT,A0		; initialise la routine d'int	LOAD.B	SMIDI1,#MASTRST		; reset de l'usart	LOAD.B	SMIDI1,#MIDIMOD!ERCVINT	; active l'interrupt	.W	LIB,?GETCAR	LOAD.B	SMIDI1,#MIDIMOD		; dactive l'interrupt	LOAD.L	D4,(A6)+OLDATA	.W	LIB,?AFX8	.W	LIB,?AFCR	LOAD.L	D3,D4	COMP.L	D3,#200	JUMP,LO 50$	LOAD.L	D3,#20050$:	LOAD.L	A4,#(A6)+OBUFFERLOOP:	TEST.L	D3	JUMP,EQ FINI	DEC.L	D3	LOAD.B	D4,(A4+)	.W	LIB,?AFX2	.W	LIB,?AFSPACE	JUMP	LOOPFINI:	EXIT;--------\\; ROUTINT >;--------/; Routine d'interruption lit MIDI et signal lorsque le nombre; de byte dsir est atteint.; in	-; out	-; mod	-ROUTINT:	PUSHM.L	D0..D4,D7,A0,A1,A6	LOAD.L	A6,#R16"VAR		;  A6 <-- ^variables	LOAD.B	D0,SMIDI1		; D0 <-- status	TEST.L	D0:#BUSIREQ		; interrupt request ?	JUMP,BC 90$			; non => 90$	LOAD.B	D1,D0	AND.B	D1,#2^BUSFERR!2^BUSOERR!2^BUSPERR	JUMP,EQ 10$;;?	LOAD.B	(A6)+OIERR,D0	JUMP	90$10$:	LOAD.B	D0,MIDI1		; D0 <-- lit le byte	LOAD.L	A0,#(A6)+OBUFFER	LOAD.L	D1,(A6)+OLDATA	COMP.L	D1,#LGMAX	JUMP,HS 90$	LOAD.B	(A0)+(D1.L),D0	INC.L	(A6)+OLDATA90$:	POPM.L	D0..D4,D7,A0,A1,A6	RETSFVAR:	.FILLB	LGVAR,0	.END	START